                isEditing={isEditingMovement}
                currentMovementId={currentMovementId}
                products={products}
                clearMovementForm={clearMovementForm}
            />
            <StockMovementList 
                movements={movements} 
                onEdit={handleEditMovement} 
            />
        </div>
    );
};
